prefil_data.body:
var sourceData = e.args[1]?.data;
console.log("Source Data", sourceData);
if (!sourceData) return;

const templateId = e.data?.template_id || 'raw_material_master';
console.log(templateId, "TEMPLATE NAME");

e.data.raw_material = {"value": e.args[1]?.id, "label": e.args[1].label};

for (let i = 0; i <= 20; i++) {
    if (templateId === 'raw_material_master') {
        const keysToClear = [
            `spec__${i}__spec`, `spec__${i}__char`, `spec__${i}__observation`, `spec__${i}__remarks`
        ];
        keysToClear.forEach(key => {
            e.data[key] = "";
            const node = e.store?.form?.componentTree?.findByKey(key);
            if (node && node.store) node.store.value = "";
        });
        e.data[`spec__${i}__ok`] = false;
    } else {
        const keysToClear = [
            `specs__${i}__characteristics`, `specs__${i}__tol_pos`, `specs__${i}__tol_neg`, `specs__${i}__is_optional`, `specs__${i}____str_value`, `specs__${i}__s1`, `specs__${i}__s2`, `specs__${i}__s3`, `specs__${i}__s4`, `specs__${i}__s5`, `spec__${i}__ok`, `specs__${i}__is_single_val`
        ];
        keysToClear.forEach(key => {
            e.data[key] = "";
            const node = e.store?.form?.componentTree?.findByKey(key);
            if (node && node.store) node.store.value = "";
        });
    }
}

e.data.sap_code = sourceData.sap_code;
e.data.indian_standard = sourceData.indian_standard;

let rowCount = 0;

if (templateId === 'raw_material_master') {
    const rawData = sourceData.specs || [];
    const filteredData = rawData.filter(item => {
        const char = item.characteristics || "";
        return char.trim() !== "";
    });
    for (let i = 0; i < filteredData.length; i++) {
        const item = filteredData[i];
        e.data[`spec__${i}__is_range`] = item.is_range;
        let specificationValue = "";
        if (item.is_range) {
            specificationValue = `${item.min ?? ''} - ${item.max ?? ''}`;
            e.data[`spec__${i}__ok`] = false;
        } else {
            specificationValue = item.specification || "";
        }
        e.data[`spec__${i}__spec`] = specificationValue;
        e.data[`spec__${i}__char`] = item.characteristics || "";
        e.data[`spec__${i}__is_optional`] = item.is_optional !== undefined ? item.is_optional : "";
        rowCount += 1;
    }
    e.data.row_count_standard = rowCount > 0 ? rowCount : 0;
} else {
    const rawDimData = sourceData.specs || [];
    const filteredDimData = rawDimData.filter(item => {
        const char = item.characteristics || "";
        return char.trim() !== "";
    });
    console.log("filteredDimData", filteredDimData);
    for (let i = 0; i < filteredDimData.length; i++) {
        const item = filteredDimData[i];
        e.data[`specs__${i}__characteristics`] = item.characteristics || "";
        e.data[`specs__${i}__tol_pos`] = item.tol_pos !== undefined ? item.tol_pos : "";
        e.data[`specs__${i}__tol_neg`] = item.tol_neg !== undefined ? item.tol_neg : "";
        e.data[`specs__${i}__str_value`] = item.str_val !== undefined ? item.str_val : "";
        e.data[`specs__${i}__is_optional`] = item.is_optional !== undefined ? item.is_optional : "";
        e.data[`specs__${i}__is_single_val`] = item.is_single_val !== undefined ? item.is_single_val : "";
        rowCount += 1;
    }
    e.data.row_count_dimensional = rowCount > 0 ? rowCount : 0;
}

load_raw_material_data.body:
const [searchValue, loadCallback, currentDataLength] = e.args;
const templateId = e.data?.template_id;
if (!templateId) {
    if (typeof loadCallback === 'function') loadCallback([]);
    return;
}

const callKey = `${templateId}_${searchValue || ''}`;

if (window._lastMaterialCallKey === callKey) {
    return;
}

if (window._materialDropdownDebounceTimer) {
    clearTimeout(window._materialDropdownDebounceTimer);
}
if (window._materialDropdownAbortController) {
    window._materialDropdownAbortController.abort();
}
window._materialDropdownAbortController = new AbortController();
const signal = window._materialDropdownAbortController.signal;

window._materialDropdownDebounceTimer = setTimeout(async () => {
    let savedToken = localStorage.getItem('dlms_auth_token');

    const apiEndpoint = templateId === 'raw_material_master_2'
        ? 'https://dlms-api.iotnp.com/api/v1/templates/raw-material-master-2/dropdown'
        : 'https://dlms-api.iotnp.com/api/v1/templates/raw_material_master/dropdown';

    let requestBody = {
        "fields": ["main__data"],
        "filters": [],
        "search": [],
        "flat": false,
        "status": "completed",
        "limit": 100
    };

    if (searchValue) {
        requestBody.search = [searchValue];
        requestBody.search_fields = ["main__data__material_name"];
    }

    try {
        const res = await fetch(apiEndpoint, {
            method: 'POST',
            headers: {
                'accept': 'application/json',
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${savedToken}`
            },
            body: JSON.stringify(requestBody),
            signal: signal
        });
        const response = await res.json();
        const items = Array.isArray(response.data) ? response.data : [];

        const uniqueMap = new Map();
        items.forEach(item => {
            const materialName = item.main?.data?.material_name;
            console.log(materialName);
            if (materialName && !uniqueMap.has(materialName)) {
                uniqueMap.set(materialName, {
                    value: materialName,
                    label: materialName,
                    id: item._id,
                    data: {
                        _id: item._id,
                        material_name: materialName,
                        indian_standard: item.main?.data?.indian_standard || "",
                        sap_code: item.main?.data?.sap_code || "",
                        specs: item.main?.data?.specs || [],
                        dimensional_specs: item.main?.data?.dimensional_specs || [],
                        _raw: item
                    }
                });
            }
        });

        const preparedData = [...uniqueMap.values()].slice(0, 200);

        window._lastMaterialCallKey = callKey;

        if (typeof loadCallback === 'function') loadCallback(preparedData);

    } catch (err) {
        if (err.name !== 'AbortError') {
            window._lastMaterialCallKey = null;
            console.error(err);
        }
        if (typeof loadCallback === 'function') loadCallback([]);
    }
}, 300);

