auto_check_ok.body:
const idx = args.row_index;
const specKey    = `spec__${idx}__spec`;
const isRangeKey = `spec__${idx}__is_range`;
const okKey      = `spec__${idx}__ok`;
const obsValue   = e.args[0];

const isRange = e.data[isRangeKey];
if (!isRange) return;

const specStr = e.data[specKey] || '';
// Matches '97 - 100', '97-100', '0.5 - 1.2' etc.
const match = specStr.match(/^([\d.]+)\s*-\s*([\d.]+)$/);
if (!match) return;

const minVal   = parseFloat(match[1]);
const maxVal   = parseFloat(match[2]);
const observed = parseFloat(obsValue);

if (isNaN(observed) || isNaN(minVal) || isNaN(maxVal)) {
    e.data[okKey] = false;
} else {
    e.data[okKey] = observed >= minVal && observed <= maxVal;
}
// Keep unicode indicator in sync
e.data[`derived__${okKey}_check`] = e.data[okKey] ? '✓' : 'x';

